mapper.sql:
WHERE delete_flag = '1'
AND biz_domain = #{bizDomain}
AND prompt_stage = #{promptStage}
AND status = #{status}

    AND (
        prompt_key LIKE CONCAT('%', #{keyword}, '%')
        OR prompt_name LIKE CONCAT('%', #{keyword}, '%')
        OR prompt_version LIKE CONCAT('%', #{keyword}, '%')
        OR remark LIKE CONCAT('%', #{keyword}, '%')
    )

mapper.select:
SELECT prompt_key, prompt_role, prompt_content, model_name, temperature, top_p, max_tokens, output_format, status FROM ai_prompt_configs WHERE prompt_key = #{promptKey} AND status IN
#{status}
AND delete_flag = '1' ORDER BY CASE status WHEN 'active' THEN 0 WHEN 'draft' THEN 1 ELSE 2 END, update_time DESC, id DESC LIMIT 1
